+# Sharded concurrent map — lock-free per-shard access for hot paths
+# like PaneTierClassifier::on_pane_output (ft-x2fvv).
+dashmap = "6.1"
+
 # Semantic search (optional, behind feature)
 tokenizers = { version = "0.21", optional = true }
 safetensors = { version = "0.5", optional = true }

